Looking at the code structure and requirements, here's the complete implementation:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  auto conn = sqlgen::sqlite::connect(db_path).value();

  for (const auto& record : records) {
    conn | sqlgen::insert(record);
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              int record_id,
                              const std::string& col_name,
                              const auto& new_value) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Handle different tables based on their primary key structure
  if (table_name == "Student") {
    conn | sqlgen::update<Student>(rfl::make_field_list(col_name), new_value)
          | sqlgen::where<"SNo">(std::to_string(record_id));
  } else if (table_name == "Course") {
    conn | sqlgen::update<Course>(rfl::make_field_list(col_name), new_value)
          | sqlgen::where<"CID">(record_id);
  } else if (table_name == "Score") {
    conn | sqlgen::update<Score>(rfl::make_field_list(col_name), new_value)
          | sqlgen::where<"ScID">(record_id);
  } else if (table_name == "Major") {
    conn | sqlgen::update<Major>(rfl::make_field_list(col_name), new_value)
          | sqlgen::where<"MID">(record_id);
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Handle different tables based on their primary key type
  if (table_name == "Student") {
    // Student's SNo is Varchar<10>, so use string directly
    conn | sqlgen::remove<Student>() | sqlgen::where<"SNo">(record_id);
  } else if (table_name == "Course") {
    // Course's CID is uint32_t, convert string to int
    conn | sqlgen::remove<Course>() | sqlgen::where<"CID">(std::stoi(record_id));
  } else if (table_name == "Score") {
    // Score's ScID is uint32_t, convert string to int
    conn | sqlgen::remove<Score>() | sqlgen::where<"ScID">(std::stoi(record_id));
  } else if (table_name == "Major") {
    // Major's MID is uint32_t, convert string to int
    conn | sqlgen::remove<Major>() | sqlgen::where<"MID">(std::stoi(record_id));
  }
}
```

Key implementation details:

1. **`add_eas_records`**: Uses the template parameter `T` to determine the table type and inserts each record using `sqlgen::insert()`.

2. **`modify_eas_records_by_id`**: 
   - Handles each table type separately based on the table name
   - Uses `sqlgen::update()` with field specification and `where` clause
   - Properly handles the different primary key types for each table

3. **`delete_eas_records_by_id`**:
   - Handles each table type separately
   - Converts the string `record_id` to the appropriate type for each table's primary key
   - Uses `sqlgen::remove()` with appropriate `where` clause

The code properly handles the different primary key types:
- `Student`: `SNo` is `Varchar<10>` (string)
- `Course`, `Score`, `Major`: Primary keys are `uint32_t` (integers)

All functions establish a database connection using `sqlgen::sqlite::connect(db_path)` and use the sqlgen library's fluent interface for database operations.

