```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  // Connect to the database
  sqlgen::SQLiteDB db("test_db.sqlite");

  try {
    // Begin transaction
    db.exec("BEGIN TRANSACTION");

    // Check if sender has sufficient funds
    auto sender = db.select_one<Account>(sqlgen::where(&Account::account_id == from_account_id));
    if (!sender || sender->balance < amount) {
      db.exec("ROLLBACK");
      return false;
    }

    // Update sender's balance (deduct amount)
    db.update<Account>(sqlgen::set(&Account::balance = sender->balance - amount),
                      sqlgen::where(&Account::account_id == from_account_id));

    // Update receiver's balance (add amount)
    auto receiver = db.select_one<Account>(sqlgen::where(&Account::account_id == to_account_id));
    if (!receiver) {
      db.exec("ROLLBACK");
      return false;
    }

    db.update<Account>(sqlgen::set(&Account::balance = receiver->balance + amount),
                      sqlgen::where(&Account::account_id == to_account_id));

    // Commit transaction
    db.exec("COMMIT");
    return true;

  } catch (const std::exception& e) {
    // Rollback on any error
    db.exec("ROLLBACK");
    return false;
  }
}

}  // namespace transaction_transfer_funds
