  sqlgen::PrimaryKey<int> user_id;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

bool upsert_user_profile(const UserProfile& u) {
  try {
    // Connect to the SQLite database
    sqlgen::SQLiteDB db("test_db.sqlite");

    // First try to insert
    try {
      auto insert_stmt = db.prepare<R"(
        INSERT INTO UserProfile (user_id, bio, avatar_url) 
        VALUES (?, ?, ?)
      )">();

      insert_stmt.bind(1, u.user_id);
      insert_stmt.bind(2, u.bio.value_or(""));
      insert_stmt.bind(3, u.avatar_url.value_or(""));

      insert_stmt.execute();

    } catch (const std::exception&) {
      // Insert failed (likely due to primary key constraint), so update instead
      auto update_stmt = db.prepare<R"(
        UPDATE UserProfile 
        SET bio = ?, avatar_url = ? 
        WHERE user_id = ?
      )">();

      update_stmt.bind(1, u.bio.value_or(""));
      update_stmt.bind(2, u.avatar_url.value_or(""));
      update_stmt.bind(3, u.user_id);

      update_stmt.execute();
    }

    return true;

  } catch (const std::exception& e) {
    // Handle any database errors
    return false;
  }
}

} // namespace upsert_user_profile
```

The first implementation using `INSERT OR REPLACE` is the most efficient and recommended approach as it handles the upsert operation in a single SQL statement, which is atomic and avoids potential race conditions. The `sqlgen` library should support this SQLite-specific syntax.

