 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  try {
    // Connect to SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Create table if it doesn't exist
    conn.execute(R"(
      CREATE TABLE IF NOT EXISTS Inventory (
        item_id INTEGER PRIMARY KEY,
        name VARCHAR(100) NOT NULL,
        quantity INTEGER NOT NULL
      )
    )");

    // Perform upsert operations using insert_or_replace
    sqlgen::insert_or_replace(conn, items);

    // Verify upsert behavior by reading back all items
    auto read_items = sqlgen::select<Inventory>(conn, "");

    // Check if all inserted items are present and correct
    for (const auto& original_item : items) {
      bool found = false;
      for (const auto& read_item : read_items) {
        if (read_item.item_id == original_item.item_id) {
          found = true;
          // Verify the data matches
          if (read_item.name != original_item.name || 
              read_item.quantity != original_item.quantity) {
            std::cerr << "Verification failed for item_id: " << original_item.item_id.value() 
                      << ". Data mismatch after upsert." << std::endl;
            return false;
          }
          break;
        }
      }

      if (!found) {
        std::cerr << "Verification failed for item_id: " << original_item.item_id.value() 
                  << ". Item not found after upsert." << std::endl;
        return false;
      }
    }

    std::cout << "Upsert operation completed successfully. " 
              << items.size() << " items processed." << std::endl;
    return true;

  } catch (const std::exception& e) {
    std::cerr << "Error in upsert_inventory_items: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace upsert_inventory_items
