 * Returns: std::vector<Event>.
 */
std::vector<Event> limit_recent_events(size_t n = 10) {
  // Create database connection
  sqlgen::Database<sqlgen::SQLite> db("test_db.sqlite");

  // Create query to select events, order by timestamp descending, and apply limit
  auto query = sqlgen::query<Event>(db)
    .order_by(&Event::created_at, sqlgen::DESC)
    .limit(n);

  // Execute query and return results
  return query.select_all();
}

