Here's the complete implementation of the `analyze_social_network` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>
#include <iostream>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

struct UserFriendCount {
  int user_id;
  std::string username;
  int friend_count;
};

struct MutualFriends {
  std::string user1_name;
  std::string user2_name;
  int mutual_friends_count;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    std::vector<FriendConnection> results;

    try {
        // Create SQLite database connection
        sqlgen::SQLiteDB db("test_db.sqlite");

        // Drop existing tables if they exist
        db.execute("DROP TABLE IF EXISTS Friendship");
        db.execute("DROP TABLE IF EXISTS User");

        // Create User table
        db.execute(R"(
            CREATE TABLE User (
                user_id INTEGER PRIMARY KEY,
                username VARCHAR(50) NOT NULL UNIQUE,
                email VARCHAR(100) NOT NULL UNIQUE,
                join_date DATETIME NOT NULL,
                city VARCHAR(50)
            )
        )");

        // Create Friendship table
        db.execute(R"(
            CREATE TABLE Friendship (
                user_id1 INTEGER,
                user_id2 INTEGER,
                friendship_date DATETIME NOT NULL,
                PRIMARY KEY (user_id1, user_id2),
                FOREIGN KEY (user_id1) REFERENCES User(user_id),
                FOREIGN KEY (user_id2) REFERENCES User(user_id)
            )
        )");

        // Insert users
        for (const auto& user : users) {
            if (user.city.has_value()) {
                db.execute("INSERT INTO User (user_id, username, email, join_date, city) VALUES (?, ?, ?, ?, ?)",
                          user.user_id, user.username, user.email, user.join_date, user.city.value());
            } else {
                db.execute("INSERT INTO User (user_id, username, email, join_date, city) VALUES (?, ?, ?, ?, NULL)",
                          user.user_id, user.username, user.email, user.join_date);
            }
        }

        // Insert friendships
        for (const auto& friendship : friendships) {
            db.execute("INSERT INTO Friendship (user_id1, user_id2, friendship_date) VALUES (?, ?, ?)",
                      friendship.user1_id, friendship.user2_id, friendship.created_at);
        }

        // 1. Find mutual friends using SELF-JOIN
        auto mutual_friends = db.query<MutualFriends>(R"(
            SELECT u1.username, u2.username, COUNT(f1.user_id2) as mutual_friends_count
            FROM User u1
            INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
            INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
            INNER JOIN User u2 ON f2.user_id2 = u2.user_id
            WHERE u1.user_id < u2.user_id
              AND EXISTS (
                SELECT 1 FROM Friendship f3 
                WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
              )
            GROUP BY u1.user_id, u2.user_id
            HAVING COUNT(f1.user_id2) > 0
        )");

        std::cout << "Mutual Friends Analysis:" << std::endl;
        for (const auto& mf : mutual_friends) {
            std::cout << mf.user1_name << " and " << mf.user2_name 
                      << " have " << mf.mutual_friends_count << " mutual friends" << std::endl;
        }

        // 2. Find users with more than average friends using nested query
        auto popular_users = db.query<UserFriendCount>(R"(
            SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
            FROM User u
            LEFT JOIN Friendship f ON u.user_id = f.user_id1
            GROUP BY u.user_id, u.username
            HAVING friend_count > (
                SELECT AVG(friend_count) 
                FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1) as friend_counts
            )
            ORDER BY friend_count DESC
        )");

        std::cout << "\nUsers with more than average friends:" << std::endl;
        for (const auto& user : popular_users) {
            std::cout << user.username << " has " << user.friend_count << " friends" << std::endl;
        }

        // 3. Find friend-of-friend relationships
        auto fof_connections = db.query<FriendConnection>(R"(
            SELECT DISTINCT u1.username as user1_name, u3.username as user2_name
            FROM User u1
            JOIN Friendship f1 ON u1.user_id = f1.user_id1
            JOIN User u2 ON f1.user_id2 = u2.user_id
            JOIN Friendship f2 ON u2.user_id = f2.user_id1
            JOIN User u3 ON f2.user_id2 = u3.user_id
            WHERE u1.user_id != u3.user_id
              AND NOT EXISTS (
                SELECT 1 FROM Friendship f3 
                WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id
              )
        )");

        std::cout << "\nFriend-of-Friend Relationships (recommendations):" << std::endl;
        for (const auto& conn : fof_connections) {
            std::cout << conn.user1_name << " -> " << conn.user2_name << std::endl;
            results.push_back(conn);
        }

        // 4. Count friends per user and identify most connected users
        auto friend_counts = db.query<UserFriendCount>(R"(
            SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
            FROM User u
            LEFT JOIN Friendship f ON u.user_id = f.user_id1
            GROUP BY u.user_id, u.username
            ORDER BY friend_count DESC
        )");

        std::cout << "\nFriend Counts (Most Connected Users):" << std::endl;
        for (const auto& user : friend_counts) {
            std::cout << user.username << ": " << user.friend_count << " friends" << std::endl;
        }

        // 5. Find users in the same city who are not yet friends
        auto city_recommendations = db.query<FriendConnection>(R"(
            SELECT u1.username as user1_name, u2.username as user2_name
            FROM User u1
            JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id
            WHERE u1.city IS NOT NULL 
              AND u2.city IS NOT NULL
              AND NOT EXISTS (
                SELECT 1 FROM Friendship f 
                WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
                   OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
              )
        )");

        std::cout << "\nSame City Recommendations:" << std::endl;
        for (const auto& rec : city_recommendations) {
            std::cout << rec.user1_name << " and " << rec.user2_name 
                      << " are in the same city but not friends" << std::endl;
        }

    } catch (const std::exception& e) {
        std::cerr << "Database error: " << e.what() << std::endl;
    }

    return results;
}

}  // namespace analyze_social_network
```

This implementation:

1. **Creates the required tables** with proper constraints and foreign keys
2. **Inserts the provided data** into the tables
3. **Performs all the required analyses**:
   - Mutual friends using SELF-JOIN
   - Users with more than average friends using nested queries
   - Friend-of-friend relationships
   - Friend counts per user
   - Same-city recommendations
4. **Uses proper SQLite error handling**
5. **Returns the friend-of-friend relationships** as specified in the return type
6. **Includes console output** to display the analysis results

The function connects to "test_db.sqlite", creates the necessary tables, populates them with data, and performs comprehensive social network analysis using the specified SQL techniques.

