bool inventory_bulk_write_and_read(const std::vector<Inventory>& items) {
    try {
        // Connect to SQLite database
        sqlgen::SQLiteDB db("test_db.sqlite");

        // Create table object
        sqlgen::Table<Inventory> inventory_table(db);

        // Drop and recreate the table to ensure clean state
        inventory_table.drop();
        inventory_table.create();

        // Bulk write records
        for (const auto& item : items) {
            inventory_table.insert(item);
        }

        // Read records with filtering and ordering
        // Filter: quantity > 50, Order: quantity DESC
        auto results = inventory_table.select(
            sqlgen::columns(&Inventory::item_id, &Inventory::name, 
                           &Inventory::quantity, &Inventory::location),
            sqlgen::where(sqlgen::gt(&Inventory::quantity, 50)),
            sqlgen::order_by(sqlgen::desc(&Inventory::quantity))
        );

        // Return true if at least one item is found
        return !results.empty();

    } catch (const std::exception& e) {
        // Handle any database errors
        return false;
    }
}

}  // namespace inventory_bulk_write_and_read
