std::vector<Result> column_is_null_checks() {
  // Connect to the SQLite database
  sqlgen::sqlite::connection db("test_db.sqlite");

  // Create the Profile table if it doesn't exist (as per assumption it exists)
  db.create_table<Profile>();

  // Query 1: Filter rows where bio IS NULL
  auto null_bio_profiles = db.query<Profile>(
    sqlgen::select<Profile>()
    .where(sqlgen::is_null(&Profile::bio))
  );

  // Query 2: Filter rows where avatar_url IS NOT NULL
  auto not_null_avatar_profiles = db.query<Profile>(
    sqlgen::select<Profile>()
    .where(sqlgen::is_not_null(&Profile::avatar_url))
  );

  // Combine and convert results
  std::vector<Result> results;

  // Add profiles with NULL bio
  for (const auto& profile : null_bio_profiles) {
    results.push_back(Result{
      .profile_id = profile.profile_id,
      .display_name = profile.display_name
    });
  }

  // Add profiles with NOT NULL avatar_url
  for (const auto& profile : not_null_avatar_profiles) {
    results.push_back(Result{
      .profile_id = profile.profile_id,
      .display_name = profile.display_name
    });
  }

  return results;
}

}  // namespace column_is_null_checks
