  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  try {
    // Connect to SQLite database
    sqlgen::sqlite::database db("test_db.sqlite");

    // Create Account table
    db.create_table_if_not_exists<Account>();

    // Insert some test data
    Account account1{1, 1000.0, "active"};
    Account account2{2, 500.0, "inactive"};
    Account account3{3, 750.0, "pending"};

    db.insert(account1);
    db.insert(account2);
    db.insert(account3);

    // Update balances and statuses using set operations
    // Example 1: Update balance for a specific account
    db.update<Account>()
      .set(&Account::balance, 1500.0)
      .where(sqlgen::column(&Account::account_id) == 1)
      .execute();

    // Example 2: Update multiple columns for a specific account
    db.update<Account>()
      .set(&Account::balance, 800.0)
      .set(&Account::status, "active")
      .where(sqlgen::column(&Account::account_id) == 2)
      .execute();

    // Example 3: Update based on condition (increase balance for active accounts)
    db.update<Account>()
      .set(&Account::balance, sqlgen::column(&Account::balance) + 100.0)
      .where(sqlgen::column(&Account::status) == "active")
      .execute();

    // Example 4: Update status for accounts with balance above threshold
    db.update<Account>()
      .set(&Account::status, "premium")
      .where(sqlgen::column(&Account::balance) > 1000.0)
      .execute();

    // Verify changes persisted
    auto results = db.select<Account>()
                   .where(sqlgen::column(&Account::account_id) > 0)
                   .order_by(&Account::account_id)
                   .execute();

    // Check if updates were successful
    bool success = true;

    for (const auto& account : results) {
      std::cout << "Account ID: " << account.account_id 
                << ", Balance: " << account.balance 
                << ", Status: " << account.status << std::endl;

      // Verify specific updates
      if (account.account_id == 1) {
        success = success && (account.balance == 1600.0); // 1500 + 100 from active bonus
        success = success && (account.status == "premium"); // Balance > 1000
      } else if (account.account_id == 2) {
        success = success && (account.balance == 800.0);
        success = success && (account.status == "active");
      } else if (account.account_id == 3) {
        success = success && (account.balance == 750.0); // Not active, no bonus
        success = success && (account.status == "pending");
      }
    }

    return success;

  } catch (const std::exception& e) {
    std::cerr << "Error in update_set_operations: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace update_set_operations
```

